code.Python3:
import sys

def main():
    data=sys.stdin.read().splitlines()
    if not data:
        return
    T=int(data[0])
    out=[]
    for i in range(1,T+1):
        name=data[i].strip()
        out.append(f"Hello, {name}!".upper())
    sys.stdout.write("\n".join(out))

if __name__=="__main__":
    main()

